import React, { useState } from "react";
import doctorService from "../../services/doctor.service";

const initialAvailability = {
  date: "",
  startTime: "09:00",
  endTime: "17:00",
  slotDuration: 30
};

function AvailabilityManager() {
  const [doctorId, setDoctorId] = useState("");
  const [form, setForm] = useState(initialAvailability);
  const [list, setList] = useState([]);
  const [slotsDate, setSlotsDate] = useState("");
  const [slots, setSlots] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");

  const setFeedback = (ok, text) => {
    setError(ok ? "" : text);
    setMessage(ok ? text : "");
  };

  const loadAvailabilities = async () => {
    if (!doctorId) {
      setFeedback(false, "Doctor ID is required.");
      return;
    }
    try {
      const response = await doctorService.getAvailabilities(doctorId);
      setList(response.data || []);
      setFeedback(true, "Availability list loaded.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Failed to load availability list.");
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!doctorId) {
      setFeedback(false, "Doctor ID is required.");
      return;
    }

    try {
      await doctorService.setAvailability(doctorId, {
        ...form,
        slotDuration: Number(form.slotDuration)
      });
      setFeedback(true, "Availability saved.");
      await loadAvailabilities();
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Failed to set availability.");
    }
  };

  const handleDelete = async (availabilityId) => {
    try {
      await doctorService.deleteAvailability(doctorId, availabilityId);
      setFeedback(true, "Availability deleted.");
      await loadAvailabilities();
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Delete failed.");
    }
  };

  const handleLoadSlots = async () => {
    if (!doctorId || !slotsDate) {
      setFeedback(false, "Doctor ID and date are required to load slots.");
      return;
    }
    try {
      const response = await doctorService.getAvailableSlots(doctorId, slotsDate);
      setSlots(response.data || []);
      setFeedback(true, "Available slots loaded.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Failed to load available slots.");
    }
  };

  return (
    <section className="card">
      <h2>Availability Management</h2>

      <div className="inline-row">
        <input
          placeholder="Doctor ID"
          value={doctorId}
          onChange={(e) => setDoctorId(e.target.value)}
        />
        <button type="button" onClick={loadAvailabilities}>Load All</button>
      </div>

      <form onSubmit={handleSubmit} className="grid-form">
        <input
          type="date"
          value={form.date}
          onChange={(e) => setForm((prev) => ({ ...prev, date: e.target.value }))}
          required
        />
        <input
          type="time"
          value={form.startTime}
          onChange={(e) => setForm((prev) => ({ ...prev, startTime: e.target.value }))}
          required
        />
        <input
          type="time"
          value={form.endTime}
          onChange={(e) => setForm((prev) => ({ ...prev, endTime: e.target.value }))}
          required
        />
        <input
          type="number"
          min="5"
          value={form.slotDuration}
          onChange={(e) => setForm((prev) => ({ ...prev, slotDuration: e.target.value }))}
          required
        />
        <button type="submit">Save Availability</button>
      </form>

      <div className="inline-row">
        <input
          type="date"
          value={slotsDate}
          onChange={(e) => setSlotsDate(e.target.value)}
        />
        <button type="button" onClick={handleLoadSlots}>Load Available Slots</button>
      </div>

      {message && <p className="ok">{message}</p>}
      {error && <p className="error">{error}</p>}

      <h3>All Availabilities</h3>
      <ul className="list">
        {list.map((item) => (
          <li key={item.id}>
            {item.availableDate} {item.startTime} - {item.endTime} ({item.slotDuration} min)
            <button type="button" onClick={() => handleDelete(item.id)}>
              Delete
            </button>
          </li>
        ))}
      </ul>

      <h3>Slots for Selected Date</h3>
      <pre className="result">{JSON.stringify(slots, null, 2)}</pre>
    </section>
  );
}

export default AvailabilityManager;
